41	 * 1. CONTEXT
42	 *
43	 * This section defines the "contexts" that are available in the backend API.
44	 *
45	 * These allow you to access things when processing a request, like the database, the session, etc.
46	 *
47	 * This helper generates the "internals" for a tRPC context. The API handler and RSC clients each
48	 * wrap this and provides the required context.
49	 *
50	 * @see https://trpc.io/docs/server/context
51	 */
52	
53	/**
54	 * Unified tRPC context factory (Clerk auth only)
55	 *
56	 * API key auth is handled by the REST layer (withApiKeyAuth, withDualAuth),
57	 * not tRPC. The CLI uses REST endpoints, not tRPC procedures.
58	 */
59	export const createTRPCContext = async (opts: { headers: Headers }) => {
60	  const clerkSession = await auth({ treatPendingAsSignedOut: false });
61	
62	  if (clerkSession.userId) {
63	    if (clerkSession.orgId) {
64	      return {
65	        auth: {
66	          type: "clerk-active" as const,
67	          userId: clerkSession.userId,
68	          orgId: clerkSession.orgId,
69	        },
70	        db,
71	        headers: opts.headers,
72	      };
73	    }
74	    return {
75	      auth: {
76	        type: "clerk-pending" as const,
77	        userId: clerkSession.userId,
78	      },
79	      db,
80	      headers: opts.headers,
81	    };
82	  }
83	
84	  return {
85	    auth: { type: "unauthenticated" as const },
86	    db,
87	    headers: opts.headers,
88	  };
89	};
