2	 * Dual Authentication Middleware for API Routes
3	 *
4	 * Supports both API key and Clerk session authentication.
5	 * - API key: Uses withApiKeyAuth, org resolved from DB (no X-Org-ID needed)
6	 * - Session: Validates org membership via Clerk
7	 */
8	
9	import { LIGHTFAST_API_KEY_PREFIX } from "@repo/app-api-key";
10	import { auth } from "@vendor/clerk/server";
11	import { log } from "@vendor/observability/log/next";
12	import type { NextRequest } from "next/server";
13	import { withApiKeyAuth } from "./with-api-key-auth";
14	
15	export interface DualAuthContext {
16	  apiKeyId?: string;
17	  authType: "api-key" | "session";
18	  clerkOrgId: string;
19	  userId: string;
20	}
21	
22	export interface DualAuthSuccess {
23	  auth: DualAuthContext;
24	  success: true;
25	}
26	
27	export interface DualAuthError {
28	  error: {
29	    code: string;
30	    message: string;
31	  };
32	  status: number;
33	  success: false;
34	}
35	
36	export type DualAuthResult = DualAuthSuccess | DualAuthError;
37	
38	/**
39	 * Verify authentication via API key OR Clerk session
40	 *
41	 * Priority:
42	 * 1. API key (Authorization: Bearer sk-lf-...) - for external clients, org from DB
43	 * 2. Clerk session - for console UI
44	 *
45	 * For API key auth: org resolved from key's DB record (no headers needed)
46	 * For session auth: validates org membership via Clerk
47	 */
48	export async function withDualAuth(
49	  request: NextRequest,
50	  requestId?: string
51	): Promise<DualAuthResult> {
52	  const authHeader = request.headers.get("authorization");
53	  if (authHeader?.startsWith("Bearer ")) {
54	    const token = authHeader.slice(7);
55	
56	    // API key path — org resolved from DB via key lookup
57	    if (token.startsWith(LIGHTFAST_API_KEY_PREFIX)) {
58	      const apiKeyResult = await withApiKeyAuth(request, requestId);
59	      if (!apiKeyResult.success) {
60	        return apiKeyResult;
61	      }
62	
63	      return {
64	        success: true,
65	        auth: {
66	          clerkOrgId: apiKeyResult.auth.orgId,
67	          userId: apiKeyResult.auth.userId,
68	          authType: "api-key",
69	          apiKeyId: apiKeyResult.auth.apiKeyId,
70	        },
71	      };
72	    }
73	
74	    // Unrecognized bearer token format — reject
75	    log.warn("Unrecognized bearer token format", { requestId });
76	    return {
77	      success: false,
78	      error: {
79	        code: "UNAUTHORIZED",
80	        message:
81	          "Invalid bearer token. Use an API key (sk-lf-...) or sign in via session.",
82	      },
83	      status: 401,
84	    };
85	  }
86	
87	  // Session path — validate via Clerk
88	  const { userId } = await auth();
89	
90	  if (!userId) {
91	    log.warn("No authentication provided", { requestId });
92	    return {
93	      success: false,
94	      error: {
95	        code: "UNAUTHORIZED",
96	        message:
97	          "Authentication required. Provide 'Authorization: Bearer <api-key>' header or sign in.",
98	      },
99	      status: 401,
100	    };
101	  }
102	
103	  const clerkOrgId = request.headers.get("x-org-id");
104	  if (!clerkOrgId) {
105	    log.warn("Missing X-Org-ID for session auth", { requestId, userId });
106	    return {
107	      success: false,
108	      error: {
109	        code: "BAD_REQUEST",
110	        message: "Org ID required. Provide 'X-Org-ID: <clerk-org-id>' header.",
111	      },
112	      status: 400,
113	    };
114	  }
115	
116	  // Verify org membership
117	  const { getCachedUserOrgMemberships } = await import("@repo/app-clerk-cache");
118	  const userMemberships = await getCachedUserOrgMemberships(userId);
119	  const isMember = userMemberships.some((m) => m.organizationId === clerkOrgId);
120	
121	  if (!isMember) {
122	    log.warn("User not member of org", { requestId, userId, clerkOrgId });
123	    return {
124	      success: false,
125	      error: {
126	        code: "FORBIDDEN",
127	        message: "Access denied to this organization",
128	      },
129	      status: 403,
130	    };
131	  }
132	
133	  log.info("Session auth verified", { requestId, userId, clerkOrgId });
134	  return {
135	    success: true,
136	    auth: { clerkOrgId, userId, authType: "session" },
137	  };
138	}
139	
140	/**
141	 * Helper to create error response from DualAuthError
142	 */
143	export function createDualAuthErrorResponse(
144	  result: DualAuthError,
145	  requestId: string
146	): Response {
147	  return Response.json(
148	    {
149	      error: result.error.code,
150	      message: result.error.message,
151	      requestId,
152	    },
153	    { status: result.status }
154	  );
155	}
