import { ORPCError, os } from "@orpc/server";
import { LIGHTFAST_API_KEY_PREFIX } from "@repo/app-api-key";
import { auth } from "@vendor/clerk/server";
import { enrichContext } from "@vendor/observability/context";
import { log } from "@vendor/observability/log/next";
import { createORPCObservabilityMiddleware } from "@vendor/observability/orpc";
import type { NextRequest } from "next/server";
import { withApiKeyAuth } from "./with-api-key-auth";

export interface InitialContext {
  headers: Headers;
  requestId: string;
}

export interface AuthContext {
  apiKeyId: string | undefined;
  authType: "api-key" | "session";
  clerkOrgId: string;
  userId: string;
}

const base = os.$context<InitialContext>();

async function resolveAuth(
  headers: Headers,
  requestId: string
): Promise<AuthContext> {
  const authHeader = headers.get("authorization");

  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.slice(7);

    if (token.startsWith(LIGHTFAST_API_KEY_PREFIX)) {
      const apiKeyResult = await withApiKeyAuth(
        { headers } as NextRequest,
        requestId
      );

      if (!apiKeyResult.success) {
        throw new ORPCError("UNAUTHORIZED", {
          message: apiKeyResult.error.message,
        });
      }

      return {
        clerkOrgId: apiKeyResult.auth.orgId,
        userId: apiKeyResult.auth.userId,
        authType: "api-key",
        apiKeyId: apiKeyResult.auth.apiKeyId,
      };
    }

    throw new ORPCError("UNAUTHORIZED", {
      message:
        "Invalid bearer token. Use an API key (sk-lf-...) or sign in via session.",
    });
  }

  // Session path — validate via Clerk
  const { userId } = await auth();

  if (!userId) {
    throw new ORPCError("UNAUTHORIZED", {
      message:
        "Authentication required. Provide 'Authorization: Bearer <api-key>' header or sign in.",
    });
  }

  const clerkOrgId = headers.get("x-org-id");
  if (!clerkOrgId) {
    throw new ORPCError("BAD_REQUEST", {
      message: "Org ID required. Provide 'X-Org-ID: <clerk-org-id>' header.",
    });
  }

  const { getCachedUserOrgMemberships } = await import("@repo/app-clerk-cache");
  const userMemberships = await getCachedUserOrgMemberships(userId);
  const isMember = userMemberships.some((m) => m.organizationId === clerkOrgId);

  if (!isMember) {
    log.warn("User not member of org", { requestId, userId, clerkOrgId });
    throw new ORPCError("FORBIDDEN", {
      message: "Access denied to this organization",
    });
  }

  log.info("Session auth verified", { requestId, userId, clerkOrgId });
  return {
    clerkOrgId,
    userId,
    authType: "session",
    apiKeyId: undefined,
  };
}

export const observabilityMiddleware = base.middleware(
  createORPCObservabilityMiddleware()
);

export const authMiddleware = base.middleware(async ({ context, next }) => {
  const authContext = await resolveAuth(context.headers, context.requestId);
  enrichContext({
    userId: authContext.userId,
    clerkOrgId: authContext.clerkOrgId,
    authType: authContext.authType,
    ...(authContext.apiKeyId && { apiKeyId: authContext.apiKeyId }),
  });
  return next({ context: authContext });
});

export const authed = base.use(authMiddleware);

/**
 * Dual Authentication Middleware for API Routes
 *
 * Supports both API key and Clerk session authentication.
 * - API key: Uses withApiKeyAuth, org resolved from DB (no X-Org-ID needed)
 * - Session: Validates org membership via Clerk
 */

import { LIGHTFAST_API_KEY_PREFIX } from "@repo/app-api-key";
import { auth } from "@vendor/clerk/server";
import { log } from "@vendor/observability/log/next";
import type { NextRequest } from "next/server";
import { withApiKeyAuth } from "./with-api-key-auth";

export interface DualAuthContext {
  apiKeyId?: string;
  authType: "api-key" | "session";
  clerkOrgId: string;
  userId: string;
}

export interface DualAuthSuccess {
  auth: DualAuthContext;
  success: true;
}

export interface DualAuthError {
  error: {
    code: string;
    message: string;
  };
  status: number;
  success: false;
}

export type DualAuthResult = DualAuthSuccess | DualAuthError;

/**
 * Verify authentication via API key OR Clerk session
 *
 * Priority:
 * 1. API key (Authorization: Bearer sk-lf-...) - for external clients, org from DB
 * 2. Clerk session - for console UI
 *
 * For API key auth: org resolved from key's DB record (no headers needed)
 * For session auth: validates org membership via Clerk
 */
export async function withDualAuth(
  request: NextRequest,
  requestId?: string
): Promise<DualAuthResult> {
  const authHeader = request.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.slice(7);

    // API key path — org resolved from DB via key lookup
    if (token.startsWith(LIGHTFAST_API_KEY_PREFIX)) {
      const apiKeyResult = await withApiKeyAuth(request, requestId);
      if (!apiKeyResult.success) {
        return apiKeyResult;
      }

      return {
        success: true,
        auth: {
          clerkOrgId: apiKeyResult.auth.orgId,
          userId: apiKeyResult.auth.userId,
          authType: "api-key",
          apiKeyId: apiKeyResult.auth.apiKeyId,
        },
      };
    }

    // Unrecognized bearer token format — reject
    log.warn("Unrecognized bearer token format", { requestId });
    return {
      success: false,
      error: {
        code: "UNAUTHORIZED",
        message:
          "Invalid bearer token. Use an API key (sk-lf-...) or sign in via session.",
      },
      status: 401,
    };
  }

  // Session path — validate via Clerk
  const { userId } = await auth();

  if (!userId) {
    log.warn("No authentication provided", { requestId });
    return {
      success: false,
      error: {
        code: "UNAUTHORIZED",
        message:
          "Authentication required. Provide 'Authorization: Bearer <api-key>' header or sign in.",
      },
      status: 401,
    };
  }

  const clerkOrgId = request.headers.get("x-org-id");
  if (!clerkOrgId) {
    log.warn("Missing X-Org-ID for session auth", { requestId, userId });
    return {
      success: false,
      error: {
        code: "BAD_REQUEST",
        message: "Org ID required. Provide 'X-Org-ID: <clerk-org-id>' header.",
      },
      status: 400,
    };
  }

  // Verify org membership
  const { getCachedUserOrgMemberships } = await import("@repo/app-clerk-cache");
  const userMemberships = await getCachedUserOrgMemberships(userId);
  const isMember = userMemberships.some((m) => m.organizationId === clerkOrgId);

  if (!isMember) {
    log.warn("User not member of org", { requestId, userId, clerkOrgId });
    return {
      success: false,
      error: {
        code: "FORBIDDEN",
        message: "Access denied to this organization",
      },
      status: 403,
    };
  }

  log.info("Session auth verified", { requestId, userId, clerkOrgId });
  return {
    success: true,
    auth: { clerkOrgId, userId, authType: "session" },
  };
}

/**
 * Helper to create error response from DualAuthError
 */
export function createDualAuthErrorResponse(
  result: DualAuthError,
  requestId: string
): Response {
  return Response.json(
    {
      error: result.error.code,
      message: result.error.message,
      requestId,
    },
    { status: result.status }
  );
}

import { getCachedUserOrgMemberships } from "@repo/app-clerk-cache";
import { auth } from "@vendor/clerk/server";
import { redirect } from "next/navigation";

export const dynamic = "force-dynamic";

/**
 * Post-login relay page.
 *
 * Auth app always lands here after sign-in/sign-up. We determine
 * the right destination server-side so there's no client-side delay:
 *
 * - Has active org in JWT → /:orgSlug (returning user, org already active)
 * - Has org memberships (cached) → first org's slug (returning user, JWT stale)
 * - No orgs → /account/teams/new (new user, needs to create a team)
 */
export default async function WelcomePage() {
  const { userId, orgSlug } = await auth();

  if (orgSlug) {
    redirect(`/${orgSlug}`);
  }

  if (userId) {
    const memberships = await getCachedUserOrgMemberships(userId);
    const first = memberships.find((m) => m.organizationSlug);
    if (first?.organizationSlug) {
      redirect(`/${first.organizationSlug}`);
    }
  }

  redirect("/account/teams/new");
}

